      const dataFormat = SOUND_MIME_TO_FORMAT[blob.type] ?? storage.DataFormat.MP3;
      const asset      = storage.createAsset(
        storage.AssetType.Sound, dataFormat,
        new Uint8Array(await blob.arrayBuffer()), null, true
      );
      try {
        await vm.addSound({ asset, md5: `${asset.assetId}.${asset.dataFormat}`, name: assetName }, stage.id);
      } catch (e) { console.error("Failed to add sound to stage:", e); }
